// src/components/InternshipModal.jsx
import React, { useState, useEffect } from "react";

export default function InternshipModal({ isOpen, onClose, onSave, initialData }) {
  const [form, setForm] = useState({
    title: "",
    company: "",
    category: "",
    mode: "",
    location: "",
    description: "",
    link: "",
  });

  useEffect(() => {
    if (initialData) setForm(initialData);
  }, [initialData]);

  const handleChange = (e) => setForm({ ...form, [e.target.name]: e.target.value });

  const handleSubmit = () => {
    onSave(form);
    onClose();
  };

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50">
      <div className="bg-white p-6 rounded-xl w-full max-w-md shadow-lg relative">
        <h2 className="text-xl font-bold mb-4">{initialData ? "Edit Internship" : "Add Internship"}</h2>

        <div className="space-y-3">
          <div>
            <label className="block text-sm font-medium">Title</label>
            <input type="text" name="title" value={form.title} onChange={handleChange} className="w-full border rounded px-3 py-2" />
          </div>
          <div>
            <label className="block text-sm font-medium">Company</label>
            <input type="text" name="company" value={form.company} onChange={handleChange} className="w-full border rounded px-3 py-2" />
          </div>
          <div>
            <label className="block text-sm font-medium">Category</label>
            <input type="text" name="category" value={form.category} onChange={handleChange} className="w-full border rounded px-3 py-2" />
          </div>
          <div>
            <label className="block text-sm font-medium">Mode</label>
            <select name="mode" value={form.mode} onChange={handleChange} className="w-full border rounded px-3 py-2">
              <option value="">Select</option>
              <option value="Remote">Remote</option>
              <option value="Onsite">Onsite</option>
              <option value="Hybrid">Hybrid</option>
            </select>
          </div>
          <div>
            <label className="block text-sm font-medium">Location</label>
            <input type="text" name="location" value={form.location} onChange={handleChange} className="w-full border rounded px-3 py-2" />
          </div>
          <div>
            <label className="block text-sm font-medium">Description</label>
            <textarea name="description" value={form.description} onChange={handleChange} rows="3" className="w-full border rounded px-3 py-2"></textarea>
          </div>
          <div>
            <label className="block text-sm font-medium">Apply Link</label>
            <input type="text" name="link" value={form.link} onChange={handleChange} className="w-full border rounded px-3 py-2" />
          </div>
        </div>

        <div className="flex justify-end mt-4 space-x-2">
          <button onClick={onClose} className="px-4 py-2 rounded bg-gray-400 text-white hover:bg-gray-500">Cancel</button>
          <button onClick={handleSubmit} className="px-4 py-2 rounded bg-green-600 text-white hover:bg-green-700">Save</button>
        </div>
      </div>
    </div>
  );
}
